from matplotlib import pyplot as pltimport numpy as npfrom skimage import io, data, img_as_float, img_as_ubytefrom skimage.filters import threshold_multiotsuimage = img_as_float(io.imread("../data/BSE_Google.jpg"), 0)plt.imshow(image, cmap = "gray")thresh  = threshold_multiotsu(image, classes =5)regions = np.digitize(image, bins = thresh)output = img_as_ubyte(regions)plt.imsave("../data/multi_otsu.jpg", output)fig, ax = plt.subplots(nrows =1 , ncols = 3, figsize = (10,3.5))# Plotting the original image.ax[0].imshow(image, cmap='gray')ax[0].set_title('Original')ax[0].axis('off')# Plotting the histogram and the two thresholds obtained from# multi-Otsu.ax[1].hist(image.ravel(), bins=255)ax[1].set_title('Histogram')for i in thresh:    ax[1].axvline(i, color='r')# Plotting the Multi Otsu result.ax[2].imshow(regions, cmap='Accent')ax[2].set_title('Multi-Otsu result')ax[2].axis('off')plt.subplots_adjust()plt.show()